#pragma once

#include "envoy/http/filter.h"
#include "envoy/server/filter_config.h"

#include "source/extensions/filters/http/common/pass_through_filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace PassThrough {

/**
 * A minimal HTTP decoder filter that passes all data through unchanged.
 * Inherits from Http::StreamDecoderFilter via PassThroughDecoderFilter.
 */
class PassThroughFilter : public Http::PassThroughDecoderFilter {
public:
  PassThroughFilter() = default;

  // Http::StreamFilterBase
  void onDestroy() override {}

  // Http::StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers,
                                          bool end_stream) override;
  Http::FilterDataStatus decodeData(Buffer::Instance& data, bool end_stream) override;
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap& trailers) override;
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override {
    decoder_callbacks_ = &callbacks;
  }
};

} // namespace PassThrough
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "pass_through_filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace PassThrough {

Http::FilterHeadersStatus PassThroughFilter::decodeHeaders(Http::RequestHeaderMap& /*headers*/,
                                                           bool /*end_stream*/) {
  return Http::FilterHeadersStatus::Continue;
}

Http::FilterDataStatus PassThroughFilter::decodeData(Buffer::Instance& /*data*/,
                                                     bool /*end_stream*/) {
  return Http::FilterDataStatus::Continue;
}

Http::FilterTrailersStatus PassThroughFilter::decodeTrailers(
    Http::RequestTrailerMap& /*trailers*/) {
  return Http::FilterTrailersStatus::Continue;
}

} // namespace PassThrough
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

#include "envoy/registry/registry.h"
#include "envoy/server/filter_config.h"

#include "source/extensions/filters/http/common/factory_base.h"

#include "pass_through_filter.h"

#include "google/protobuf/struct.pb.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace PassThrough {

/**
 * Config factory for the pass-through HTTP filter.
 * Follows the NamedHttpFilterConfigFactory pattern used by other Envoy filters.
 */
class PassThroughFilterConfig
    : public Common::FactoryBase<Protobuf::Struct> {
public:
  PassThroughFilterConfig() : FactoryBase("envoy.filters.http.pass_through") {}

private:
  Http::FilterFactoryCb createFilterFactoryFromProtoTyped(
      const Protobuf::Struct& /*proto_config*/, const std::string& /*stats_prefix*/,
      Server::Configuration::FactoryContext& /*context*/) override {
    return [](Http::FilterChainFactoryCallbacks& callbacks) -> void {
      callbacks.addStreamDecoderFilter(std::make_shared<PassThroughFilter>());
    };
  }
};

/**
 * Static registration for the pass-through filter. @see RegisterFactory.
 */
REGISTER_FACTORY(PassThroughFilterConfig, Server::Configuration::NamedHttpFilterConfigFactory);

} // namespace PassThrough
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

