    27→PerRouteHeaderMutation::PerRouteHeaderMutation(const PerRouteProtoConfig& config)
    28→    : mutations_(config.mutations()) {}
    29→
    30→HeaderMutationConfig::HeaderMutationConfig(const ProtoConfig& config)
    31→    : mutations_(config.mutations()),
    32→      most_specific_header_mutations_wins_(config.most_specific_header_mutations_wins()) {}
    33→
    34→Http::FilterHeadersStatus HeaderMutation::decodeHeaders(Http::RequestHeaderMap& headers, bool) {
    35→  Formatter::HttpFormatterContext ctx{&headers};
    36→  config_->mutations().mutateRequestHeaders(headers, ctx, decoder_callbacks_->streamInfo());
    37→
    38→  // Traverse through all route configs to retrieve all available header mutations.
    39→  // `getAllPerFilterConfig` returns in ascending order of specificity (i.e., route table
    40→  // first, then virtual host, then per route).
    41→  route_configs_ = Http::Utility::getAllPerFilterConfig<PerRouteHeaderMutation>(decoder_callbacks_);
    42→
    43→  if (!config_->mostSpecificHeaderMutationsWins()) {
    44→    // most_specific_wins means that most specific level per filter config is evaluated last. In
    45→    // other words, header mutations are evaluated in ascending order of specificity (same order as
    46→    // `getAllPerFilterConfig` above returns).
    47→    // Thus, here we reverse iterate the vector when `most_specific_wins` is false.
    48→    for (auto it = route_configs_.rbegin(); it != route_configs_.rend(); ++it) {
    49→      (*it)->mutations().mutateRequestHeaders(headers, ctx, decoder_callbacks_->streamInfo());
    50→    }
    51→  } else {
    52→    for (const auto* route_config : route_configs_) {
    53→      route_config->mutations().mutateRequestHeaders(headers, ctx,
    54→                                                     decoder_callbacks_->streamInfo());
    55→    }
    56→  }
    57→
    58→  return Http::FilterHeadersStatus::Continue;
    59→}
    60→
    61→Http::FilterHeadersStatus HeaderMutation::encodeHeaders(Http::ResponseHeaderMap& headers, bool) {
    62→  Formatter::HttpFormatterContext ctx{encoder_callbacks_->requestHeaders().ptr(), &headers};
    63→  config_->mutations().mutateResponseHeaders(headers, ctx, encoder_callbacks_->streamInfo());
    64→
    65→  // If we haven't already traversed the route configs, do so now.
    66→  if (route_configs_.empty()) {
    67→    route_configs_ =
    68→        Http::Utility::getAllPerFilterConfig<PerRouteHeaderMutation>(encoder_callbacks_);
    69→  }
    70→
    71→  if (!config_->mostSpecificHeaderMutationsWins()) {
    72→    for (auto it = route_configs_.rbegin(); it != route_configs_.rend(); ++it) {
    73→      (*it)->mutations().mutateResponseHeaders(headers, ctx, encoder_callbacks_->streamInfo());
    74→    }
    75→  } else {
    76→    for (const auto* route_config : route_configs_) {
    77→      route_config->mutations().mutateResponseHeaders(headers, ctx,
    78→                                                      encoder_callbacks_->streamInfo());
    79→    }
    80→  }
    81→
    82→  return Http::FilterHeadersStatus::Continue;
    83→}
