#pragma once

#include "envoy/http/filter.h"
#include "envoy/server/filter_config.h"

#include "source/extensions/filters/http/common/pass_through_filter.h"

namespace Envoy {
namespace Extensions {
namespace HttpFilters {
namespace PassThrough {

/**
 * A minimal HTTP decoder filter that passes all data through unchanged.
 * Inherits from Http::StreamDecoderFilter via PassThroughDecoderFilter.
 */
class PassThroughFilter : public Http::PassThroughDecoderFilter {
public:
  PassThroughFilter() = default;

  // Http::StreamFilterBase
  void onDestroy() override {}

  // Http::StreamDecoderFilter
  Http::FilterHeadersStatus decodeHeaders(Http::RequestHeaderMap& headers,
                                          bool end_stream) override;
  Http::FilterDataStatus decodeData(Buffer::Instance& data, bool end_stream) override;
  Http::FilterTrailersStatus decodeTrailers(Http::RequestTrailerMap& trailers) override;
  void setDecoderFilterCallbacks(Http::StreamDecoderFilterCallbacks& callbacks) override {
    decoder_callbacks_ = &callbacks;
  }
};

} // namespace PassThrough
} // namespace HttpFilters
} // namespace Extensions
} // namespace Envoy

